print("=== Rhetorical Role Labeling on Full Judgment ===\n")

device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
print(f"Using device: {device}")

with open("tag2idx.json") as f:
    tag2idx = json.load(f)
idx2tag = {v: k for k, v in tag2idx.items()}

model = MTL_Classifier(
    n_tags=len(tag2idx),
    sent_emb_dim=768,
    sos_tag_idx=tag2idx['<start>'],
    eos_tag_idx=tag2idx['<end>'],
    pad_tag_idx=tag2idx['<pad>'],
    device=device
).to(device)

checkpoint = torch.load("model_state.tar", map_location=device, weights_only=False)
model.load_state_dict(checkpoint['state_dict'])
model.eval()
print("✅ Model loaded successfully!\n")

