# Split into clean sentences
sentences = [s.strip() for s in sent_tokenize(full_text) if len(s.strip()) > 15]

print(f"Found {len(sentences)} sentences in the judgment.\n")
print("=== PREDICTIONS ===\n")

tokenizer = BertTokenizer.from_pretrained("bert-base-uncased")
bert_model = BertModel.from_pretrained("bert-base-uncased").to(device)
bert_model.eval()

with torch.no_grad():
    # Generate embeddings
    gen_embs = []
    for sent in sentences:
        marked = "[CLS] " + sent + " [SEP]"
        tokenized = tokenizer.encode(marked, max_length=512, truncation=True, padding="max_length")
        tokens_tensor = torch.tensor([tokenized]).to(device)
        output = bert_model(tokens_tensor)
        cls_emb = output.last_hidden_state[0][0].cpu().numpy()
        gen_embs.append(cls_emb)

    # 2304-dim for binary emitter
    s_embs = []
    for i in range(len(gen_embs)):
        prev = gen_embs[i-1] if i > 0 else np.zeros(768)
        curr = gen_embs[i]
        nxt = gen_embs[i+1] if i < len(gen_embs)-1 else np.zeros(768)
        s_embs.append(np.concatenate((prev, curr, nxt)))

    batch_x = [gen_embs]
    batch_x_binary = [s_embs]

    pred, = model(batch_x, batch_x_binary)

    # Print results
    for i, (sent, role_id) in enumerate(zip(sentences, pred)):
        role = idx2tag[role_id]
        print(f"{i+1:3d}. {sent[:120]:120} → {role}")

print("\n🎉 Full judgment processed successfully!")